import type { InputCompactProps, InputCompactSlots, InputRootEmits, InputUi } from '@soybeanjs/headless/input';
import type { ClassValue } from '@soybeanjs/headless/types';
import type { ThemeSize } from '@/theme';

/**
 * Properties for the Input component.
 */
export interface InputProps extends InputCompactProps {
  /**
   * root class
   */
  class?: ClassValue;
  /**
   * Visual size of the component.
   */
  size?: ThemeSize;
  /**
   * Per-slot class overrides for the component.
   */
  ui?: Partial<InputUi>;
}

/**
 * Events for the Input component.
 */
export type InputEmits = InputRootEmits;

/**
 * Slots for the Input component.
 */
export type InputSlots = InputCompactSlots;

// @unocss-include
import { scv } from '@soybeanjs/cva';
import { miniButtonIconVariants } from './button';

export const inputVariants = scv({
  extendBase: props => ({
    clear: miniButtonIconVariants({ size: props.size, shape: 'circle' })
  }),
  slots: {
    root: [
      `group flex items-center w-full rounded-md border border-solid border-input bg-background transition-all-150`,
      `outline-none focus-within:ring-3 focus-within:ring-offset-background focus-within:ring-primary/30`
    ],
    control: [
      'grow min-w-0 h-full bg-transparent outline-none',
      'placeholder:text-muted-foreground',
      'disabled:cursor-not-allowed disabled:opacity-50',
      'file:border-0 file:bg-transparent file:font-medium'
    ],
    clear: [
      'hidden shrink-0 opacity-50',
      'group-hover:inline-flex group-focus-within:inline-flex hover:opacity-100 focus-visible:opacity-100'
    ],
    visible: 'shrink-0 cursor-pointer'
  },
  variants: {
    size: {
      xs: {
        root: 'h-6 px-1.5 text-2xs gap-1',
        control: 'file:py-1.25'
      },
      sm: {
        root: 'h-7 px-2 text-xs gap-1.5',
        control: 'file:py-1.25'
      },
      md: {
        root: 'h-8 px-2.5 text-sm gap-2',
        control: 'file:py-1.25'
      },
      lg: {
        root: 'h-9 px-3 text-base gap-2.5',
        control: 'file:py-1.25'
      },
      xl: {
        root: 'h-10 px-3.5 text-lg gap-3',
        control: 'file:py-1.25'
      },
      '2xl': {
        root: 'h-12 px-4 text-xl gap-3.5',
        control: 'file:py-2'
      }
    }
  },
  defaultVariants: {
    size: 'md'
  }
});
